import{_ as e,o as t,c as l,af as r}from"./chunks/framework.SW4JcFcZ.js";const c=JSON.parse('{"title":"NAT测试工具","description":"","frontmatter":{"title":"NAT测试工具","date":"2025-04-14T20:34:44.000Z","excerpt":"pystun3-gui是一个基于Python的NAT类型检测工具，提供图形界面，方便用户快速检测网络NAT类型。","tags":["Python","网络工具","开源项目"],"categories":["开源项目"]},"headers":[],"relativePath":"blog/posts/NAT测试工具.md","filePath":"blog/posts/NAT测试工具.md","lastUpdated":null}'),i={name:"blog/posts/NAT测试工具.md"};function o(n,a,s,h,d,u){return t(),l("div",null,[...a[0]||(a[0]=[r('<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>在网络应用开发中，了解当前网络的NAT类型对于P2P通信和网络连接性诊断非常重要。pystun3-gui项目提供了一个简单易用的图形界面工具，帮助用户快速检测NAT类型。</p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>pystun3-gui是一个基于Python开发的NAT类型检测工具，它是对pystun3库的图形界面封装。该工具具有以下特点：</p><ol><li>简洁的图形用户界面</li><li>支持自定义STUN服务器</li><li>可显示本地IP和公网IP信息</li><li>多线程设计，避免界面卡顿</li><li>跨平台支持（Windows/Linux/MacOS）</li></ol><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><h3 id="nat类型检测" tabindex="-1">NAT类型检测 <a class="header-anchor" href="#nat类型检测" aria-label="Permalink to &quot;NAT类型检测&quot;">​</a></h3><p>工具可以检测并显示以下信息：</p><ul><li>本地IP地址</li><li>公网IP地址</li><li>NAT类型（如Full Cone、Restricted Cone、Port Restricted Cone、Symmetric等）</li></ul><h3 id="自定义服务器" tabindex="-1">自定义服务器 <a class="header-anchor" href="#自定义服务器" aria-label="Permalink to &quot;自定义服务器&quot;">​</a></h3><p>用户可以：</p><ul><li>使用默认STUN服务器</li><li>输入自定义STUN服务器地址和端口</li><li>保存常用服务器配置</li></ul><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><div id="note1"></div> [1] STUN（Session Traversal Utilities for NAT）是一种网络协议，用于发现NAT（Network Address Translation，网络地址转换）的存在并获取翻译后的公网IP地址。 <h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li><a href="https://github.com/chenzd123456/pystun3-gui" target="_blank" rel="noreferrer">pystun3-gui项目地址</a></li><li><a href="https://pypi.org/project/pystun3/" target="_blank" rel="noreferrer">pystun3库文档</a></li><li><a href="https://tools.ietf.org/html/rfc3489" target="_blank" rel="noreferrer">STUN协议 - RFC 3489</a></li></ol>',17)])])}const T=e(i,[["render",o]]);export{c as __pageData,T as default};
